const data = $input.first().json;

let templateId = data.body?.template || data.template_id || data.template;
let layers = data.body?.layers || data.layers;

// Clean the layers string
if (typeof layers === 'string') {
  layers = layers.replace(/\\n/g, '');
  layers = layers.replace(/\n/g, '');
  layers = layers.trim();

  try {
    layers = JSON.parse(layers);
  } catch (e) {
    return { json: { error: 'Parse failed: ' + e.message } };
  }
}

// Return complete JSON body as string
return {
  json: {
    requestBody: JSON.stringify({
      template: templateId,
      layers: layers,
      format: "png"
    })
  }
};

// n8n Code Node: Extract template layers and validate agent input

// ===== PART 1: Extract template layers with defaults =====
// Change 'Get Template layers' to your actual HTTP node name that calls the API
const templateData = $input.first().json;
const template = Array.isArray(templateData) ? templateData[0] : templateData;
const layers = template.layers || [];

// Build required layers object with defaults
const requiredLayers = {};
layers.forEach(layer => {
  if (layer.type === 'text') {
    requiredLayers[layer.layer] = { text: layer.text || "" };
  } else if (layer.type === 'image') {
    requiredLayers[layer.layer] = { image_url: layer.image_url || "" };
  } else if (layer.type === 'shape') {
    requiredLayers[layer.layer] = { fill: layer.fill || layer.color || "" };
  }
});

// ===== PART 2: Get and clean agent's layers =====
// Change 'Clear agent input' to your actual code node name
const agentData = $('Clear agent input').first().json;
let agentLayers = agentData.layers || {};

// If requestBody is a string, parse it
if (agentData.requestBody) {
  try {
    const parsed = JSON.parse(agentData.requestBody);
    agentLayers = parsed.layers || {};
  } catch (e) {}
}

// Clean agent layers if it's a string
if (typeof agentLayers === 'string') {
  agentLayers = agentLayers.replace(/\\n/g, '').replace(/\n/g, '');
  try {
    agentLayers = JSON.parse(agentLayers);
  } catch (e) {
    agentLayers = {};
  }
}

// ===== PART 3: Validate layers =====
const requiredLayerNames = Object.keys(requiredLayers);
const passedLayerNames = Object.keys(agentLayers);

const missingLayers = [];
const missingLayersWithDefaults = {};
const emptyLayers = [];
const emptyLayersWithDefaults = {};

requiredLayerNames.forEach(layerName => {
  if (!agentLayers[layerName]) {
    missingLayers.push(layerName);
    missingLayersWithDefaults[layerName] = requiredLayers[layerName];
  } else {
    const layerValue = agentLayers[layerName];
    const field = Object.keys(layerValue)[0];
    if (!layerValue[field] || layerValue[field] === '') {
      emptyLayers.push(layerName);
      emptyLayersWithDefaults[layerName] = requiredLayers[layerName];
    }
  }
});

const allPassed = missingLayers.length === 0 && emptyLayers.length === 0;

return {
  json: {
    template_id: template.id,
    valid: allPassed,
    layers_with_defaults: requiredLayers,
    missing_layers: missingLayers,
    missing_layers_with_defaults: missingLayersWithDefaults,
    empty_layers: emptyLayers,
    empty_layers_with_defaults: emptyLayersWithDefaults,
    passed_count: passedLayerNames.length,
    required_count: requiredLayerNames.length,
    message: allPassed 
      ? "All layers passed successfully" 
      : `Missing: ${missingLayers.join(', ') || 'none'}. Empty: ${emptyLayers.join(', ') || 'none'}`
  }
};

// Extract useful template information with preview - handle multiple items
// Group templates by prefix and return layers only once per group
const items = $input.all();

const allTemplates = items.flatMap(item => {
  const input = item.json;

  // Handle both array and nested response formats
  let templateList;
  if (Array.isArray(input)) {
    templateList = input;
  } else {
    templateList = input.response || input.data || input.templates || [input];
  }

  return templateList;
});

// Group templates by prefix (text before '-' in name)
const groups = {};
for (const template of allTemplates) {
  const name = template.name || '';
  let prefix, suffix;

  if (name.includes('-')) {
    const parts = name.split('-');
    prefix = parts[0].trim();
    suffix = parts.slice(1).join('-').trim();
  } else {
    prefix = name;
    suffix = '';
  }

  if (!groups[prefix]) {
    groups[prefix] = {
      templates: [],
      layers: null // Will be set from first template (all same in group)
    };
  }

  groups[prefix].templates.push({
    id: template.id,
    description: suffix, // Suffix goes in description
    preview: template.thumbnail || '',
    size: {
      width: template.width,
      height: template.height
    }
  });

  // Set layers from first template (all templates in group have same layers)
  if (!groups[prefix].layers && template.layers) {
    groups[prefix].layers = template.layers.map(layer => {
      const base = {
        name: layer.layer,
        type: layer.type,
        description: layer.description || ''
      };

      if (layer.type === 'text') {
        base.text = layer.text || '';
        base.fontFamily = layer.font_family || null;
        base.color = layer.color || null;
      } else if (layer.type === 'image') {
        base.imageUrl = layer.image_url || null;
      } else if (layer.type === 'shape') {
        base.color = layer.color || null;
      }

      return base;
    });
  }
}

// Convert groups to output format
const result = Object.entries(groups).map(([prefix, group]) => ({
  template_name: prefix,
  templates: group.templates,
  template_count: group.templates.length,
  layers: group.layers || []
}));

return result.map(t => ({ json: t }));
